{
  "domain_analysis": {
    "business_context": "A global logistics platform must implement real-time driver earnings breakdowns (base pay, per-delivery bonus, tips, deductions) across three jurisdictions with fundamentally different labor classifications, legal requirements, and institutional approval processes. This is not a simple UI feature — it is a compensation disclosure system with legal, labor relations, and tax implications that vary by jurisdiction.",
    "bounded_context": "Driver Compensation & Earnings Transparency",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed compensation component for a delivery task, calculated differently depending on driver classification (hourly wage for employees, per-task rate for contractors)" },
      { "term": "Per-Delivery Bonus", "definition": "Variable incentive pay awarded on top of base pay for completing a delivery, potentially subject to different tax treatments by jurisdiction" },
      { "term": "Tips", "definition": "Voluntary gratuities from customers passed through to drivers. Must be displayed separately from platform-sourced compensation in all jurisdictions" },
      { "term": "Deductions", "definition": "Amounts subtracted from gross earnings — includes taxes, social contributions, equipment fees, or platform fees depending on jurisdiction and classification" },
      { "term": "Driver Classification", "definition": "The legal labor status of a driver — employee (California under AB5, Germany) or independent contractor (Indonesia) — which determines what earnings components exist, how they are calculated, and what must be disclosed" },
      { "term": "Earnings Breakdown", "definition": "The itemized decomposition of a driver's compensation for a given period, showing all components from gross to net" },
      { "term": "Works Council (Betriebsrat)", "definition": "German employee representative body with co-determination rights under the Betriebsverfassungsgesetz (BetrVG). Has legal authority to approve or block changes to compensation display systems before rollout" },
      { "term": "Real-Time", "definition": "Earnings data updated and visible to the driver within the same working session or shift, not delayed to next pay cycle. Does NOT mean sub-second — means 'current shift/day, not stale'" },
      { "term": "Net Earnings", "definition": "The final amount a driver receives after all deductions. The meaning and composition differ by jurisdiction." },
      { "term": "Wage Statement", "definition": "In California, a legally mandated itemized document (Labor Code §226) that must include gross wages, total hours, deductions, net wages, pay period dates, and employer information" }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Tips must always be displayed as a separate line item, never commingled with base pay or bonuses",
      "invariant": true,
      "invariant_justification": "Commingling tips with platform-sourced pay is illegal in California (Labor Code §351), violates German wage transparency norms, and misrepresents driver earnings everywhere. If violated, the system produces a legally and factually incorrect earnings record.",
      "testable_assertion": "In every earnings breakdown rendered to a driver, tips appear as a distinct line item with its own label and amount, never summed into base pay or bonus fields"
    },
    {
      "id": "BR-2",
      "rule": "California drivers must receive an itemized earnings statement compliant with Labor Code §226, including: gross wages earned, total hours worked, all deductions with explanations, net wages, inclusive dates of pay period, and legal employer name/address",
      "invariant": true,
      "invariant_justification": "Failure to provide a compliant wage statement exposes the platform to statutory penalties of $50-$100 per pay period per employee under California law. This is a legal data integrity requirement — an incomplete statement is a compliance violation, not a policy choice.",
      "testable_assertion": "For any California-based driver, the earnings breakdown includes all six §226 required fields, and no field is null or omitted"
    },
    {
      "id": "BR-3",
      "rule": "Germany rollout must not proceed until written works council (Betriebsrat) approval is obtained and recorded in the system",
      "invariant": true,
      "invariant_justification": "Under BetrVG §87(1)(6), the works council has co-determination rights over technical systems that monitor employee performance or behavior. Compensation display systems qualify. Deploying without approval is a legal violation that the works council can enjoin through labor court, halting the feature entirely and creating legal liability.",
      "testable_assertion": "The feature flag for Germany earnings transparency cannot be enabled unless a works council approval record exists with status 'approved' and a valid approval date"
    },
    {
      "id": "BR-4",
      "rule": "Deductions displayed must correspond to the driver's legal classification: employee deductions (payroll tax, social security, health insurance) for California and Germany; contractor deductions (platform fees, equipment fees) for Indonesia",
      "invariant": true,
      "invariant_justification": "Showing employee-type deductions to contractors (or vice versa) creates legal misclassification evidence and confuses drivers about their actual tax obligations. The deduction categories are a direct encoding of the employment relationship — getting them wrong corrupts the legal meaning of the record.",
      "testable_assertion": "Given a driver's jurisdiction and classification, only deduction types valid for that classification appear in the breakdown; no cross-classification deduction types are ever shown"
    },
    {
      "id": "BR-5",
      "rule": "California drivers classified as employees under AB5 must have their base pay displayed as an hourly rate × hours worked, not as a per-task lump sum",
      "invariant": true,
      "invariant_justification": "AB5 requires employee classification, and California Labor Code §226 requires showing hourly rate and hours worked. Displaying a per-task lump sum for an employee implies contractor treatment and creates misclassification evidence.",
      "testable_assertion": "For California drivers, base pay line item displays hourly rate, hours worked, and computed total — never a single flat amount without hourly breakdown"
    },
    {
      "id": "BR-6",
      "rule": "Earnings breakdown must be available in the driver's locale language: English for California, German for Germany, Bahasa Indonesia for Indonesia",
      "invariant": false,
      "invariant_justification": "While German law requires German-language wage documents and this is good practice everywhere, the specific language list is a policy decision that could change as the platform expands to new markets.",
      "testable_assertion": "Each earnings breakdown is rendered in the primary official language of the driver's operating jurisdiction"
    },
    {
      "id": "BR-7",
      "rule": "The sum of displayed components (base pay + bonuses + tips - deductions) must equal the displayed net earnings to the cent, with no unexplained rounding discrepancy",
      "invariant": true,
      "invariant_justification": "If the arithmetic does not balance, the earnings record is internally inconsistent — the driver cannot trust any number shown. This is a data integrity constraint: a breakdown that doesn't add up is corrupt by definition.",
      "testable_assertion": "For every earnings breakdown, (base_pay + bonuses + tips) - sum(deductions) == net_earnings, with zero tolerance for discrepancy"
    },
    {
      "id": "BR-8",
      "rule": "Indonesian contractor drivers must see platform commission/fees as a deduction, not hidden in a reduced base rate",
      "invariant": false,
      "invariant_justification": "While transparency is the feature's purpose and hiding fees would undermine trust, Indonesia does not legally mandate this disclosure for contractors. This is a strong business policy but not a system integrity constraint — a VP could decide to show fees differently.",
      "testable_assertion": "For Indonesian drivers, any platform fee or commission is shown as an explicit deduction line item, not absorbed into a lower base rate"
    },
    {
      "id": "BR-9",
      "rule": "Earnings data shown in real-time must reconcile with the final pay-period settlement — any mid-period estimates must be clearly labeled as 'estimated' until finalized",
      "invariant": true,
      "invariant_justification": "If real-time figures are presented as final but later change at settlement, drivers lose trust and may have legal claims for wage discrepancy (especially in California). Labeling estimates as estimates is a data integrity requirement — presenting uncertain data as certain is misinformation.",
      "testable_assertion": "Any earnings component not yet finalized for the pay period is displayed with an 'estimated' indicator; once finalized, the indicator is removed and the amount matches the settlement record"
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery during an active shift",
      "when": "They view their earnings breakdown",
      "then": "They see: hourly rate × hours worked as base pay, per-delivery bonus amount, tips as a separate line, itemized deductions (federal tax, state tax, SDI, etc.), net earnings, pay period dates, and employer legal name — all per Labor Code §226"
    },
    {
      "id": "AC-2",
      "given": "The Germany works council has NOT yet approved the earnings transparency feature",
      "when": "A product manager or system administrator attempts to enable the feature for Germany",
      "then": "The system refuses activation and displays a message indicating works council approval is required"
    },
    {
      "id": "AC-3",
      "given": "The Germany works council HAS approved the feature (approval record exists)",
      "when": "A German driver views their earnings breakdown",
      "then": "They see base pay, bonuses, tips (separate), and employee deductions (income tax/Lohnsteuer, social contributions/Sozialabgaben, church tax if applicable) — all in German"
    },
    {
      "id": "AC-4",
      "given": "An Indonesian independent contractor driver completes deliveries",
      "when": "They view their earnings breakdown",
      "then": "They see per-task base rate, per-delivery bonuses, tips (separate), and contractor deductions (platform commission, any equipment fees) with net payout — no employee-type deductions shown"
    },
    {
      "id": "AC-5",
      "given": "A driver in any jurisdiction views their earnings during an active shift (before pay period finalization)",
      "when": "Any earnings component has not yet been finalized",
      "then": "That component is visually marked as 'estimated' and the breakdown includes a notice that final amounts are confirmed at pay period close"
    },
    {
      "id": "AC-6",
      "given": "A driver views their earnings breakdown in any jurisdiction",
      "when": "The breakdown is rendered",
      "then": "The displayed components sum correctly: base_pay + bonuses + tips - deductions = net_earnings, with zero discrepancy"
    },
    {
      "id": "AC-7",
      "given": "A driver in California has received tips from customers",
      "when": "They view their earnings breakdown",
      "then": "Tips are never added to base pay or bonus — they appear as a distinct, labeled line item"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver relocates from Indonesia to California mid-employment",
      "expected_behavior": "The system must transition the driver's classification from contractor to employee, change deduction categories, switch to hourly rate display, and apply California §226 requirements — all retroactive to the jurisdiction change date. The old Indonesian earnings history remains in contractor format; new earnings use employee format."
    },
    {
      "scenario": "Germany works council approval is revoked after feature launch",
      "expected_behavior": "The system must immediately disable the earnings transparency feature for German drivers and revert to the previous compensation display (or no display). The feature flag must check approval status dynamically, not just at initial rollout."
    },
    {
      "scenario": "A California driver works a shift that crosses midnight into a new pay period",
      "expected_behavior": "Hours and earnings must be correctly split across pay periods. The real-time breakdown must show the current pay period's earnings only, with the previous period's finalized separately."
    },
    {
      "scenario": "A customer adds a tip after the driver has already viewed their earnings for that delivery",
      "expected_behavior": "The earnings breakdown must update to include the late tip. If the pay period was already finalized, a tip adjustment must appear in the next period with clear attribution to the original delivery."
    },
    {
      "scenario": "Platform fee structure changes mid-pay-period for Indonesian drivers",
      "expected_behavior": "Deliveries completed before the change use the old fee rate; deliveries after use the new rate. The breakdown must show both rates clearly, not blend them into an average."
    },
    {
      "scenario": "A California driver's shift has zero deliveries but they were logged in and available",
      "expected_behavior": "As an AB5 employee, the driver must still see base pay (hourly rate × hours on-shift) even with zero deliveries. Bonuses and tips show as $0.00. The breakdown must not be empty or hidden."
    },
    {
      "scenario": "German driver's church tax status is unknown or not yet configured in the system",
      "expected_behavior": "The system must not guess or omit the deduction. It should flag the missing data, show other deductions accurately, and mark the church tax line as 'pending configuration' rather than showing an incorrect amount."
    }
  ],

  "business_impact": {
    "financial": "High. California non-compliance with §226 carries penalties of $50-$100 per pay period per employee, uncapped in aggregate. Germany works council violations can result in injunctions halting the feature and legal costs. Correct implementation builds driver trust, reducing churn — driver acquisition costs in logistics typically run $300-$1,500 per driver.",
    "operational": "Significant complexity. Three different calculation engines (hourly employee, salaried employee, contractor) must be maintained. Real-time computation adds infrastructure load. Works council approval process introduces a hard dependency in the Germany rollout timeline that product cannot control.",
    "user": "Directly impacts driver satisfaction and retention. Transparent earnings are the #1 requested feature in gig economy platforms. However, showing deductions that drivers did not expect (especially new contractors in Indonesia seeing explicit platform fees) may cause short-term dissatisfaction even as it builds long-term trust.",
    "risk": "Legal risk is the primary concern. Misclassification evidence (showing contractor UI to employees or vice versa) could be used in AB5 enforcement actions. Premature Germany rollout without works council approval could trigger a works council injunction and damage labor relations. Data accuracy failures in real-time earnings could generate wage dispute claims.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Gain legally mandated wage transparency; incorrect implementation could result in underpayment or confusing wage statements leading to labor complaints" },
      { "group": "Drivers (Germany)", "impact": "Feature delayed until works council approves; once live, gain clear compensation visibility in German language with proper social contribution breakdown" },
      { "group": "Drivers (Indonesia)", "impact": "Gain transparency into platform fees for the first time; may cause short-term dissatisfaction when fees are made explicit but improves long-term trust and retention" },
      { "group": "Works Council (Germany)", "impact": "Must be engaged as a decision-making stakeholder, not merely informed. Failure to involve them properly damages labor relations beyond this single feature" },
      { "group": "Legal/Compliance Team", "impact": "Must validate §226 compliance for California, co-determination compliance for Germany, and contractor classification accuracy for Indonesia before each jurisdiction goes live" },
      { "group": "Finance/Payroll Team", "impact": "Real-time earnings display must reconcile with payroll systems. Any discrepancy between what drivers see and what they're paid creates dispute resolution workload" },
      { "group": "Product/Engineering", "impact": "Must build jurisdiction-aware rendering logic, classification-driven deduction engines, and works council approval gating — significantly more complex than a single global feature" }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is dangerously underspecified for a legally sensitive feature spanning three jurisdictions. It reads as a single global feature ('show earnings breakdown') but the legal requirements make it effectively three different features with different data models, different approval processes, and different compliance obligations. Key ambiguities remain unresolved: the spec does not mention §226 compliance, works council co-determination rights, or classification-driven deduction differences — all of which are hard legal requirements, not optional enhancements. Without explicit confirmation that these legal requirements are in scope, confidence cannot exceed 55.",
    "high_confidence_areas": [
      "Tips must be separated from platform-sourced pay (universal requirement)",
      "Earnings components must sum to net (arithmetic integrity)",
      "Germany requires works council approval before deployment (well-established German labor law)",
      "California requires employee classification under AB5 (settled law since 2020)"
    ],
    "low_confidence_areas": [
      "Exact deduction categories per jurisdiction — requires legal review for each market",
      "Whether 'real-time' means per-delivery update, per-shift update, or daily update — spec does not define",
      "How estimated vs. finalized amounts should be visually distinguished — UX not specified",
      "Whether German works council approval is a one-time gate or requires ongoing renewal",
      "Tax withholding calculation accuracy — platform may not be the system of record for tax computation"
    ],
    "assumptions": [
      "California drivers are classified as employees under AB5 (spec states this)",
      "German drivers are also employees (standard for logistics platforms operating in Germany)",
      "The platform has access to real-time delivery completion and payment events",
      "Tax/deduction calculations are sourced from an authoritative payroll system, not computed by this feature",
      "The works council approval is a prerequisite gate, not a post-launch formality"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec says 'real time' but does not define the update cadence or latency tolerance. For California employees, showing stale earnings could constitute an inaccurate wage statement. Does 'real time' mean per-delivery (seconds), per-shift (hours), or per-day? This has direct infrastructure cost and legal compliance implications.",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Engineering", "Legal/Compliance"],
      "options": [
        "Per-delivery: update within 60 seconds of delivery completion — highest accuracy, highest infrastructure cost",
        "Per-shift: update at shift boundaries — lower cost but drivers see stale data mid-shift",
        "Event-driven with 'estimated' label: show best-available data labeled as estimated until finalized"
      ],
      "recommendation": "Event-driven with 'estimated' labeling. This satisfies transparency goals, manages California compliance risk by clearly marking preliminary figures, and avoids over-engineering real-time infrastructure."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not mention California Labor Code §226 itemized wage statement requirements, yet these are legally mandatory for employee drivers. Is the earnings breakdown intended to serve as or supplement the legal wage statement? If it IS the wage statement, it must include employer name/address, pay period dates, and employee ID — none of which are mentioned in the spec.",
      "affected_stakeholders": ["Drivers (California)", "Legal/Compliance", "Product"],
      "options": [
        "This feature IS the wage statement — must include all §226 fields",
        "This feature supplements a separate wage statement — can show a simplified view but the legal document must exist elsewhere",
        "Unclear — needs legal review before implementation"
      ],
      "recommendation": "Treat this feature as supplementary to, not a replacement for, the legal wage statement. But the real-time view must still not contradict the legal statement, so §226 fields should be included as a superset."
    },
    {
      "type": "missing_context",
      "description": "No information provided about whether the German works council has been engaged, their current stance, or expected approval timeline. This is a hard blocker for Germany — not a nice-to-have. The entire Germany rollout timeline depends on an external stakeholder decision that product cannot control.",
      "affected_stakeholders": ["Works Council (Germany)", "Drivers (Germany)", "Product", "Legal"],
      "options": [
        "Begin works council engagement immediately in parallel with development",
        "Build the feature for California and Indonesia first, Germany later",
        "Build Germany support but gate behind approval flag — develop now, activate when approved"
      ],
      "recommendation": "Build Germany support gated behind a works council approval flag. Develop the jurisdiction-specific logic now, but enforce a hard gate that prevents activation without recorded approval. Begin works council engagement immediately — approval processes can take 3-6 months."
    }
  ],

  "rejection_reasons": []
}

